#!/usr/bin/env node
/* sprint1.mjs — applies Sprint 1 (collection engine). Overwrites the listed files in place. */
import { mkdirSync, writeFileSync } from "node:fs";
import { dirname } from "node:path";
const FILES=[
  ["package.json", ""],
  ["PROJECT_LOG.md", ""],
  ["src/main/services/logger.ts", ""],
  ["src/main/services/extraction/oct.ts", ""],
  ["src/main/services/mca/browser.ts", ""],
  ["src/main/services/mca/collector.ts", ""],
  ["src/main/services/mca/session.ts", ""],
  ["src/main/db/documents.repo.ts", ""],
  ["src/main/ipc/index.ts", ""],
  ["src/preload/index.ts", ""],
  ["src/preload/index.d.ts", ""],
  ["src/renderer/src/App.tsx", ""],
  ["src/renderer/src/assets/main.css", ""]
];
let n=0; for(const [rel,b64] of FILES){ mkdirSync(dirname(rel),{recursive:true}); writeFileSync(rel,Buffer.from(b64,"base64")); n++; }
console.log(`✅ Sprint 1 applied: ${n} files written/updated.`);
console.log("Next: npm install  &&  npx playwright install firefox  &&  npm run dev");
